def interpretability_score(ground_truth):
    import pickle

    # Load the trained model
    with open('trained_models.pkl', 'rb') as file:
        model = pickle.load(file)

    # Assuming model has a get_feature_importance method (linear models/easy to interpret models)
    if hasattr(model, 'feature_importances_'):
        return model.feature_importances_.mean()  # average importance score
    else:
        return 0  # If model has no importance, return 0

